class Solution {
 public:
  int solve(vector<int>& preorder) {
    unordered_map<int, int> segmentTree;

    int root = preorder[0];

    for (int i = 0; i < preorder.size(); i++) {
      segmentTree[i] = preorder[i];
    }

    int index = 0;

    function<void(int, int, int)> dfs = [&] (int left, int right, int index) {
      if (left > right) return;

      int mid = (left + right) / 2;

      dfs(left, mid - 1, index * 2);
      dfs(mid + 1, right, index * 2 + 1);
    };

    dfs(0, preorder.size() - 1, 0);

    return root;
  }
 };
